<template>
  <main
    :class="
      pogoda.name != undefined && pogoda.weather[0].main == clear ? 'son' : ''
    "
  >
    <div class="input-box">
      <input type="text" v-model="neme" @keyup.enter="Weather" />
    </div>

    <div class="images"></div>

    <div class="weather" v-if="pogoda.name != undefined">
      <div class="data">
        {{ GetData.getDate() }}-{{ mounth[GetData.getMonth()] }}
      </div>
      <div class="time">
        {{ GetData.getHours() }}:{{ GetData.getMinutes() }}
      </div>
      <div class="new">
        <p>город</p>
        <div class="location">{{ pogoda.name }}| {{ pogoda.sys.country }}</div>
        <div class="temp">{{ Math.round(pogoda.main.temp / 13) }} С</div>
      </div>
      <div class="temper">
        <div class="info fas fa-clouds">
          {{ pogoda.weather[0].description }}
        </div>
        <div class="veter">Ветер {{ Math.floor(pogoda.wind.speed) }} m/s</div>
      </div>
    </div>
    <div v-else>
      <p>net takovo</p>
    </div>
    <div class="HoursWeather">
      <ul class="newWeather" v-if="pogoda.name != undefined">
        <li class="lipog" v-for="(car, i) in  newPogoda" :key="i">
          <p class="kiki"><i class="fas fa-cloud-sun"></i> {{ car.clouds }}%</p>
          <div class="weathers">{{ car.weather[0].description }}</div>
          <div class="temp_minmax">
            {{ Math.floor(car.temp.min / 3.5) }}/{{
              Math.floor(car.temp.max / 3)
            }}
            C
          </div>
          <div class="sun">
            <i class="fas fa-sunrise san"></i>
            {{ new Date(car.sunrise * 1000).toLocaleTimeString("pt-BR") }}
          </div>
          <div class="sunset">
            <i class="fas fa-sunset san"></i>
            {{ new Date(car.sunset * 1000).toLocaleTimeString("pt-BR") }}
          </div>
          <div class="date">
            {{ new Date(car.moonrise * 1000).toLocaleDateString("fr-CA") }}
          </div>
          <img    
            src="http://openweathermap.org/img/wn:{{this.newPogoda.weather[0].icon}}"
            alt=""
          />
        </li>
      </ul>
    </div>
  </main>
</template>

<script>
export default {
  data() {
    return {
      neme: "",
      url: "https://api.openweathermap.org/data/2.5/",
      Newurl: "https://pro.openweathermap.org/data/2.5/",
      key: "bd3c7192bac2843ed748223b9d01e2d7",
      Key: "6e73b5851b267d77306794727ac0fb13",
      pogoda: {},
      newPogoda: [],
      icons: "",
      GetData: new Date(),
      mounth: [
        "Января",
        "Февраля",
        "Марта",
        "Апреля",
        "Мая",
        "Июня",
        "Июля",
        "Августа",
        "Сентебря",
        "Октября",
        "Ноября",
        "Декабря",
      ],
      //https://pro.openweathermap.org/data/2.5/forecast/hourly?q={city name}&appid={API key}
    };
  },
  methods: {
    Weather() {
      fetch(
        `${this.url}weather?q=${this.neme},units=imperial&appid=${this.key}&lang=ru`
      )
        .then((res) => res.json())
        .then((data) => {
          this.pogoda = data;
          console.log(data);
          this.newWeather();
        });
    },
    newWeather() {
      fetch(
        `${this.url}onecall?lat=${this.pogoda.coord.lat}&lon=${this.pogoda.coord.lon}&units=imperial&exclude=hourly&appid=${this.key}&lang=ru`
      )
        .then((res) => res.json())
        .then((data) => {
          this.newPogoda = data.daily;
          console.log(data);
          this.icon();
        })
        .catch((err) => console.log(err));
    },
    icon() {
      fetch(
        `http://openweathermap.org/img/wn/${this.newPogoda.weather[0].icon}`
      ).then((res) => {
        this.icons = res;
        console.log(res);
      });
    },
  },
};
</script>
